import{_ as o,o as e,c as n,a2 as i}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Plugin Settings","description":"Kemoku Plugin Settings","frontmatter":{"title":"Plugin Settings","description":"Kemoku Plugin Settings","weight":90,"extra":{"order":90},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/settings"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/settings"}],["meta",{"property":"og:title","content":"Plugin Settings"}],["meta",{"property":"og:description","content":"Kemoku Plugin Settings"}],["meta",{"name":"twitter:title","content":"Plugin Settings"}],["meta",{"name":"twitter:description","content":"Kemoku Plugin Settings"}]]},"headers":[],"relativePath":"docs/kemoku/settings.md","filePath":"docs/kemoku/settings.md"}'),s={name:"docs/kemoku/settings.md"};function r(l,t,a,g,c,u){return e(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="plugin-settings" tabindex="-1">Plugin Settings <a class="header-anchor" href="#plugin-settings" aria-label="Permalink to &quot;Plugin Settings&quot;">​</a></h1><p>To customize the plugin options visit <strong>Kemoku Reviews</strong> → <strong>Settings</strong> in your WordPress Dashboard where you can define all plugin options.</p><hr><h2 id="adjusting-settings" tabindex="-1">Adjusting Settings <a class="header-anchor" href="#adjusting-settings" aria-label="Permalink to &quot;Adjusting Settings&quot;">​</a></h2><p>All default plugin settings are defined in this page. Take your time to go over each field and set the value you need. If you find a field name unclear, check the detailed information right below it.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-settings-page.webp" alt="Kemoku Plugin Settings"></p><h3 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h3><p>These settings apply to all the plugin sections.</p><p><strong>Key Settings:</strong></p><ul><li><strong>Affiliate Link Target</strong>: Choose whether affiliate links open in new tab or same tab</li><li><strong>Affiliate Link Rel Attribute</strong>: Set rel attributes for affiliate links (nofollow, noopener, etc.)</li><li><strong>Button Styling</strong>: Customize button colors, font weight, and shadow effects</li><li><strong>Rating Stars</strong>: Configure star colors and total number of stars</li><li><strong>Table Styling</strong>: Set background and font colors for table rows and grid items</li><li><strong>Collapsed Lists</strong>: Enable collapsed lists in review blocks and set initial item count</li></ul><h3 id="hero-section" tabindex="-1">Hero Section <a class="header-anchor" href="#hero-section" aria-label="Permalink to &quot;Hero Section&quot;">​</a></h3><p>These settings apply to Hero section only.</p><p><strong>Key Settings:</strong></p><ul><li><strong>Affiliate Link/Button Text</strong>: Customize the hero button text</li><li><strong>Ratings Headline</strong>: Text above the rating stars</li><li><strong>Bonus Text</strong>: Bonus information display</li><li><strong>Include Geo Section</strong>: Enable/disable country support messages in hero</li><li><strong>Hero Layout</strong>: Choose between 1 or 2 column layout</li></ul><h3 id="pros-cons" tabindex="-1">Pros &amp; Cons <a class="header-anchor" href="#pros-cons" aria-label="Permalink to &quot;Pros &amp; Cons&quot;">​</a></h3><p>These settings apply to Pros &amp; Cons section only.</p><p><strong>Key Settings:</strong></p><ul><li><strong>Pros Icon Color</strong>: Background color for pros icons</li><li><strong>Cons Icon Color</strong>: Background color for cons icons</li><li><strong>Heading Font Size</strong>: Font size for pros/cons headings</li><li><strong>Text Styling</strong>: Font size and colors for pros/cons text</li></ul><h3 id="cta-section" tabindex="-1">CTA Section <a class="header-anchor" href="#cta-section" aria-label="Permalink to &quot;CTA Section&quot;">​</a></h3><p>These settings apply to CTA section only.</p><p><strong>Key Settings:</strong></p><ul><li><strong>Block Headline</strong>: Headline for the CTA section</li><li><strong>Button Text</strong>: CTA section button text</li><li><strong>Heading Font Size</strong>: Font size for CTA headings</li><li><strong>Button Styling</strong>: Colors and styling for CTA buttons</li><li><strong>Sticky CTA Section</strong>: Display the CTA section as a sticky block at the bottom of the page on mobile devices</li></ul><h3 id="blocks-table-grid" tabindex="-1">Blocks (Table &amp; Grid) <a class="header-anchor" href="#blocks-table-grid" aria-label="Permalink to &quot;Blocks (Table &amp; Grid)&quot;">​</a></h3><p>These settings apply to Table and Grid blocks/shortcodes only.</p><p><strong>Key Settings:</strong></p><ul><li><strong>Row/Item Background Color</strong>: Background color for table rows and grid items</li><li><strong>Row/Item Font Color</strong>: Font color for table rows and grid items</li><li><strong>Button Text</strong>: Text for buttons in table/grid items</li><li><strong>Listing Tools</strong>: Configure popup text, button labels, and sorting options</li></ul><h3 id="geo-targeting" tabindex="-1">Geo Targeting <a class="header-anchor" href="#geo-targeting" aria-label="Permalink to &quot;Geo Targeting&quot;">​</a></h3><p>Plugin&#39;s Geo Targeting settings.</p><p><strong>Key Settings:</strong></p><ul><li><strong>Supported Text</strong>: Message when review supports visitor&#39;s country</li><li><strong>Unsupported Text</strong>: Message when review doesn&#39;t support visitor&#39;s country</li><li><strong>Bonus Text</strong>: Bonus information for supported countries</li><li><strong>Affiliate Link/Button Text</strong>: Button text for country support blocks</li><li><strong>Not Supported Additional Text</strong>: Alternative message for unsupported countries</li><li><strong>Page Link URL</strong>: Fallback page for unsupported countries</li><li><strong>Page Link Text</strong>: Link text for fallback pages</li><li><strong>MaxMind License Key</strong>: License key for geo-location when Cloudflare isn&#39;t available</li></ul><h3 id="color-theme" tabindex="-1">Color Theme <a class="header-anchor" href="#color-theme" aria-label="Permalink to &quot;Color Theme&quot;">​</a></h3><p>Changing a color theme will overwrite all your custom styling options.</p><p><strong>Available Themes:</strong></p><ul><li><strong>Default</strong>: Original plugin colors</li><li><strong>Blue</strong>: Blue color scheme</li><li><strong>Green</strong>: Green color scheme</li><li><strong>Red</strong>: Red color scheme</li><li><strong>Yellow</strong>: Yellow color scheme</li><li><strong>Purple</strong>: Purple color scheme</li><li><strong>Black</strong>: Black color scheme</li></ul>',34)])])}const h=o(s,[["render",r]]);export{p as __pageData,h as default};
